import React from 'react'
import Template from './Template'
import Home from '../pages/Home'


const Login = () => {

  return (
    <>
      {
        window.localStorage.getItem('isLoggedIn')===false?
        <Template
            formtype="login"
        />
        :
        <Home/>

      }
    </>
  )
}

export default Login
